// 联赛LOGO辅助函数：返回带LOGO的联赛名HTML
function leagueLogoHtml(leagueId, size) {
  const lg = FOOTBALL_LEAGUES[leagueId];
  if (!lg) return '';
  const s = size || 14;
  return `<img class="ll" style="width:${s}px;height:${s}px;object-fit:contain;vertical-align:middle;filter:drop-shadow(0 0 1px rgba(255,255,255,.15))" src="${lg.logo}" onerror="var p=this.parentNode;if(p)p.innerHTML='${lg.flag}';else this.outerHTML='${lg.flag}'">`;
}

// ==================== 时区转换工具 ====================
// 判断欧洲夏令时（3月最后一个周日 01:00 UTC → 10月最后一个周日 01:00 UTC）
function isEuropeanDST(dateStr) {
  const d = new Date(dateStr + 'T12:00:00Z'); // 用UTC中午判断，避免跨天问题
  const year = d.getUTCFullYear();
  // 3月最后一个周日
  let marLast = new Date(Date.UTC(year, 2, 31));
  while (marLast.getUTCDay() !== 0) marLast.setUTCDate(marLast.getUTCDate() - 1);
  // 10月最后一个周日
  let octLast = new Date(Date.UTC(year, 9, 31));
  while (octLast.getUTCDay() !== 0) octLast.setUTCDate(octLast.getUTCDate() - 1);
  // 夏令时：3月最后一个周日01:00 UTC → 10月最后一个周日01:00 UTC
  const dstStart = marLast.getTime() + 1 * 3600000;
  const dstEnd = octLast.getTime() + 1 * 3600000;
  return d.getTime() >= dstStart && d.getTime() < dstEnd;
}

// 将欧洲当地时间转换为北京时间
// dateStr: '2025-08-16', timeStr: '15:00', leagueId: 'PL'
// 返回: { date: '2025-08-16', time: '22:00', timestamp: ... }
function localToBJ(dateStr, timeStr, leagueId) {
  const lg = FOOTBALL_LEAGUES[leagueId];
  if (!lg) {
    // 未知联赛，直接当北京时间
    const d = new Date(dateStr + 'T' + (timeStr || '15:00') + ':00+08:00');
    return { date: dateStr, time: timeStr || '15:00', timestamp: d.getTime() };
  }

  // 世界杯数据已经是北京时间，直接解析
  if (leagueId === 'WC') {
    const d = new Date(dateStr + 'T' + (timeStr || '15:00') + ':00+08:00');
    return { date: dateStr, time: timeStr || '15:00', timestamp: d.getTime() };
  }

  // serverOnly 联赛（如中超）数据已是北京时间，直接返回
  if (lg.serverOnly) {
    const d = new Date(dateStr + 'T' + (timeStr || '15:00') + ':00+08:00');
    return { date: dateStr, time: timeStr || '15:00', timestamp: d.getTime() };
  }

  // 五大联赛+欧冠(openfootball)：将欧洲当地时间转为北京时间
  // 注：欧冠(fixturedownload)数据已在fetchCLMatches中转为北京时间，不会走到这里
  const utcOffset = lg.utcOffset || 0; // 标准UTC偏移（冬令时）
  const dst = isEuropeanDST(dateStr);
  const actualOffset = dst ? utcOffset + 1 : utcOffset; // 夏令时+1
  const bjOffset = 8; // 北京时间 UTC+8
  const diffHours = bjOffset - actualOffset; // 需要加的小时数

  // 将当地时间解析为UTC，然后加偏移得到北京时间
  // 例：英超15:00 UK → 解析为15:00 UTC → 加8h=23:00 北京
  const [h, m] = (timeStr || '15:00').split(':').map(Number);
  const localMs = new Date(dateStr + 'T00:00:00Z').getTime() + h * 3600000 + m * 60000;
  const bjMs = localMs + diffHours * 3600000;
  const bjDate = new Date(bjMs);

  // 提取北京时间的日期和时间
  const bjDateStr = bjDate.toISOString().slice(0, 10);
  const bjTimeStr = bjDate.toISOString().slice(11, 16);

  return { date: bjDateStr, time: bjTimeStr, timestamp: bjMs };
}

