// 获取世界杯赛程（静态数据，国内无需外网）
// ==================== 世界杯数据源 ====================
// 优先级：1. fixturedownload.com API → 2. 本地静态数据兜底
async function fetchWCMatches() {
  // 先尝试API获取
  try {
    const matches = await fetchWCFromApi();
    if (matches && matches.length > 0) {
      console.log('[WC] fixturedownload返回:', matches.length + '场');
      // 缓存到 cachedData，使 renderMyMatches 能搜索到世界杯比赛
      cachedData['league_WC'] = { data: { matches: matches }, ts: Date.now() };
      return matches;
    }
  } catch(e) {
    console.warn('[WC] fixturedownload失败:', e.message);
  }

  // 回退到本地静态数据
  console.log('[WC] 使用本地静态数据');
  const staticMatches = getWCStaticMatches();
  // 同样缓存到 cachedData
  cachedData['league_WC'] = { data: { matches: staticMatches }, ts: Date.now() };
  return staticMatches;
}

// 从fixturedownload.com获取世界杯数据
async function fetchWCFromApi() {
  const res = await fetchWithTimeout(WC_API_URL, 15000);
  if (!res.ok) throw new Error('HTTP ' + res.status);
  const text = await res.text();
  const rawMatches = JSON.parse(text);
  if (!rawMatches || !Array.isArray(rawMatches) || rawMatches.length === 0) {
    throw new Error('空数据');
  }

  const now = new Date();
  return rawMatches.map((m, i) => {
    // fixturedownload返回UTC时间，需转北京时间
    const utcDate = new Date(m.DateUtc + 'Z');
    const bjDate = new Date(utcDate.getTime() + 8 * 60 * 60 * 1000);
    const dateStr = bjDate.toISOString().slice(0, 10);
    const timeStr = bjDate.toTimeString().slice(0, 5);
    const matchTs = bjDate.getTime();

    // 判断状态
    const hasScore = m.HomeTeamScore !== null && m.AwayTeamScore !== null;
    const diffMin = (now - bjDate) / 60000;
    const isLive = !hasScore && diffMin >= 0 && diffMin < 120;
    const isFinished = hasScore || diffMin >= 120;

    // 队名处理：fixturedownload格式
    const homeTeam = m.HomeTeam || 'TBD';
    const awayTeam = m.AwayTeam || 'TBD';

    return {
      id: `wc_2026_api_${i}`,
      date: dateStr,
      time: timeStr,
      team1: homeTeam,
      team2: awayTeam,
      homeCn: getTeamCn(homeTeam),
      awayCn: getTeamCn(awayTeam),
      homeBadge: getTeamBadge(homeTeam),
      awayBadge: getTeamBadge(awayTeam),
      homeScore: hasScore ? m.HomeTeamScore : null,
      awayScore: hasScore ? m.AwayTeamScore : null,
      isLive: isLive,
      isFinished: isFinished,
      round: m.Group ? `${m.Group}` : `Round ${m.RoundNumber}`,
      timestamp: matchTs,
      leagueId: 'WC'
    };
  });
}

// 本地静态数据作为回退
function getWCStaticMatches() {
  const now = new Date();
  return WORLD_CUP_2026_MATCHES.map((m, i) => {
    const matchDate = new Date(m.date + 'T' + m.time + ':00+08:00');
    const isLive = now >= matchDate && now < new Date(matchDate.getTime() + 120 * 60 * 1000);
    const isFinished = now >= new Date(matchDate.getTime() + 120 * 60 * 1000);
    return {
      id: `wc_2026_${i}`,
      date: m.date,
      time: m.time,
      team1: m.team1,
      team2: m.team2,
      homeCn: getTeamCn(m.team1),
      awayCn: getTeamCn(m.team2),
      homeBadge: getTeamBadge(m.team1),
      awayBadge: getTeamBadge(m.team2),
      homeScore: null,
      awayScore: null,
      isLive: isLive,
      isFinished: isFinished,
      round: `${m.group}组 第${m.matchday}轮`,
      timestamp: matchDate.getTime(),
      leagueId: 'WC',
      group: m.group,
      matchday: m.matchday
    };
  });
}

// 获取国内杯赛赛程（7m.com.cn静态数据，时间已是北京时间）
function fetchCupMatches(leagueId) {
  const cupData = CUP_MATCHES_2025_26 && CUP_MATCHES_2025_26[leagueId];
  if (!cupData || !cupData.matches) return [];

  const now = new Date();
  return cupData.matches.map((m, i) => {
    const matchDate = new Date(m.date + 'T' + m.time + ':00+08:00'); // 数据已是北京时间
    const hasScore = m.score && m.score.length === 2;
    const isFinished = hasScore && m.score[0] !== null;
    const homeScore = hasScore ? m.score[0] : null;
    const awayScore = hasScore ? m.score[1] : null;

    return {
      id: `${leagueId}_${i}_${m.date}_${m.team1}_${m.team2}`.replace(/\s/g, '_'),
      date: m.date,
      time: m.time,
      team1: m.team1,
      team2: m.team2,
      homeCn: getTeamCn(m.team1),
      awayCn: getTeamCn(m.team2),
      homeBadge: getTeamBadge(m.team1),
      awayBadge: getTeamBadge(m.team2),
      homeScore: homeScore,
      awayScore: awayScore,
      isLive: false,
      isFinished: isFinished,
      round: m.round,
      timestamp: matchDate.getTime(),
      leagueId: leagueId
    };
  });
}
